  static AppState? of(BuildContext c) => c.dependOnInheritedWidgetOfExactType<AppState>();
  @override
  bool updateShouldNotify(AppState old) => counter != old.counter;
}

class App extends StatefulWidget {
  const App({super.key});
  @override
  State<App> createState() => _AppState();
}

class _AppState extends State<App> {
  int _c = 0;
  @override
  Widget build(BuildContext context) {
    return AppState(counter: _c, increment: () => setState(() => _c++),
      child: MaterialApp(title: 'APP_NAME', debugShowCheckedModeBanner: false,
        theme: ThemeData(colorSchemeSeed: Colors.blue, useMaterial3: true),
        home: Scaffold(appBar: AppBar(title: const Text('Inherited')),
          body: Center(child: Builder(builder: (c) => Text(
            AppState.of(c)!.counter.toString(), style: const TextStyle(fontSize: 48)))),
          floatingActionButton: FloatingActionButton(
            onPressed: () => AppState.of(context)!.increment(), child: const Icon(Icons.add)),
        )));
  }
}
void main() => runApp(const App());

