class ResponsiveLayout extends StatelessWidget {
  final Widget mobile, tablet, desktop;
  const ResponsiveLayout({super.key, required this.mobile, required this.tablet, required this.desktop});
  static bool isMobile(BuildContext c) => MediaQuery.of(c).size.width < 600;
  static bool isTablet(BuildContext c) => MediaQuery.of(c).size.width >= 600 && MediaQuery.of(c).size.width < 1200;
  static bool isDesktop(BuildContext c) => MediaQuery.of(c).size.width >= 1200;
  @override
  Widget build(BuildContext context) {
    return LayoutBuilder(builder: (context, constraints) {
      if (constraints.maxWidth >= 1200) return desktop;
      if (constraints.maxWidth >= 600) return tablet;
      return mobile;
    });
  }
}

