import 'dart:async';
import 'package:flutter/material.dart';

class CountdownTimer extends StatefulWidget {
  final int seconds;
  final VoidCallback? onComplete;
  const CountdownTimer({super.key, required this.seconds, this.onComplete});
  @override
  State<CountdownTimer> createState() => _CountdownTimerState();
}

class _CountdownTimerState extends State<CountdownTimer> {
  late int _seconds;
  Timer? _timer;
  @override
  void initState() {
    super.initState();
    _seconds = widget.seconds;
    _timer = Timer.periodic(const Duration(seconds: 1), (t) {
      if (_seconds > 0) setState(() => _seconds--);
      else { t.cancel(); widget.onComplete?.call(); }
    });
  }
  @override
  void dispose() { _timer?.cancel(); super.dispose(); }
  @override
  Widget build(BuildContext context) {
    final m = (_seconds ~/ 60).toString().padLeft(2, '0');
    final s = (_seconds % 60).toString().padLeft(2, '0');
    return Text(m + ':' + s, style: const TextStyle(fontSize: 48, fontWeight: FontWeight.bold));
  }
}

