import 'package:flutter/material.dart';

class FlipCard extends StatefulWidget {
  final Widget front, back;
  const FlipCard({super.key, required this.front, required this.back});
  @override
  State<FlipCard> createState() => _FlipCardState();
}

class _FlipCardState extends State<FlipCard> with SingleTickerProviderStateMixin {
  late AnimationController _ctrl;
  late Animation<double> _anim;
  bool _showFront = true;
  @override
  void initState() {
    super.initState();
    _ctrl = AnimationController(vsync: this, duration: const Duration(milliseconds: 600));
    _anim = Tween<double>(begin: 0, end: 1).animate(CurvedAnimation(parent: _ctrl, curve: Curves.easeInOut));
  }
  @override
  void dispose() { _ctrl.dispose(); super.dispose(); }
  @override
  Widget build(BuildContext context) {
    return GestureDetector(onTap: () {
      if (_showFront) _ctrl.forward(); else _ctrl.reverse();
      _showFront = !_showFront;
    },
      child: AnimatedBuilder(animation: _anim, builder: (_, __) {
        final angle = _anim.value * pi;
        return Transform(transform: Matrix4.identity()..setEntry(3, 1, 0.001)..rotateY(angle),
          alignment: Alignment.center,
          child: angle > pi / 2 ? Transform(transform: Matrix4.identity()..rotateY(pi), child: widget.back) : widget.front);
      }));
  }
}

