class LifecycleWidget extends StatefulWidget {
  final Widget child;
  final VoidCallback? onInit, onDispose;
  final VoidCallback? onResume, onPause;
  const LifecycleWidget({super.key, required this.child, this.onInit, this.onDispose, this.onResume, this.onPause});
  @override
  State<LifecycleWidget> createState() => _LifecycleWidgetState();
}

class _LifecycleWidgetState extends State<LifecycleWidget> with WidgetsBindingObserver {
  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addObserver(this);
    widget.onInit?.call();
  }
  @override
  void dispose() {
    WidgetsBinding.instance.removeObserver(this);
    widget.onDispose?.call();
    super.dispose();
  }
  @override
  void didChangeAppLifecycleState(AppLifecycleState state) {
    if (state == AppLifecycleState.resumed) widget.onResume?.call();
    if (state == AppLifecycleState.paused) widget.onPause?.call();
  }
  @override
  Widget build(BuildContext context) => widget.child;
}

