  Widget build(BuildContext context) {
    return Scaffold(appBar: AppBar(title: const Text('AnimatedContainer')),
      body: Center(child: GestureDetector(onTap: () => setState(() => _expanded = !_expanded),
        child: AnimatedContainer(duration: const Duration(milliseconds: 400), curve: Curves.easeInOut,
          width: _expanded ? 300 : 100, height: _expanded ? 300 : 100,
          decoration: BoxDecoration(color: _expanded ? Colors.blue : Colors.red,
            borderRadius: BorderRadius.circular(_expanded ? 100 : 16),
            boxShadow: [BoxShadow(color: (_expanded ? Colors.blue : Colors.red).withOpacity(0.3), blurRadius: 20, spreadRadius: 5)]),
          child: const Icon(Icons.touch_app, color: Colors.white, size: 40)))));
  }
}

