import 'package:flutter/material.dart';

class AnimatedBuilderPage extends StatefulWidget {
  const AnimatedBuilderPage({super.key});
  @override
  State<AnimatedBuilderPage> createState() => _AnimatedBuilderPageState();
}

class _AnimatedBuilderPageState extends State<AnimatedBuilderPage> with SingleTickerProviderStateMixin {
  late AnimationController _ctrl;
  @override
  void initState() {
    super.initState();
    _ctrl = AnimationController(vsync: this, duration: const Duration(seconds: 2))..repeat();
  }
  @override
  void dispose() { _ctrl.dispose(); super.dispose(); }
  @override
  Widget build(BuildContext context) {
    return Scaffold(appBar: AppBar(title: const Text('AnimatedBuilder')),
      body: Center(child: AnimatedBuilder(animation: _ctrl, builder: (_, child) {
        return Transform.rotate(angle: _ctrl.value * 2 * 3.14159,
          child: Container(width: 100, height: 100,
            decoration: BoxDecoration(color: Colors.blue,
              borderRadius: BorderRadius.circular(20)),
            child: child));
      }, child: const Icon(Icons.refresh, color: Colors.white, size: 40))));
  }
}
